const body = items[0].json.body || items[0].json;
const instanceUrl = body.sfInstanceUrl || '';
const rawPhone = (body.phone || '').replace(/\D/g, '');
const tokenType = body.sfTokenType || 'Bearer';
const accessToken = body.sfAccessToken || '';

// WhatsApp vem sem o 9 de celular
// Ex: 556592988342 (12 dígitos) → precisa virar 5565992988342 (13 dígitos)
// 55 + DDD(65) + 9 + resto(92988342)
let phoneWithNine = rawPhone;
if (rawPhone.length === 12 && rawPhone.startsWith('55')) {
  const withoutCountry = rawPhone.substring(2);
  const ddd = withoutCountry.substring(0, 2);
  const resto = withoutCountry.substring(2);
  phoneWithNine = '55' + ddd + '9' + resto;
}

// Pega os últimos 11 dígitos para LIKE
const phone11 = phoneWithNine.slice(-11);

const soql = `SELECT Id, Name, Phone, MobilePhone, beetalk__PhoneOrMobilePhone__c, Status, LeadSource, Company, OwnerId FROM Lead WHERE beetalk__PhoneOrMobilePhone__c LIKE '%${phone11}' LIMIT 1`;

const apiUrl = instanceUrl + '/services/data/v58.0/query/?q=' + encodeURIComponent(soql);

items[0].json.sfQueryUrl = apiUrl;
items[0].json.sfToken = tokenType + ' ' + accessToken;
items[0].json.sfInstanceUrl = instanceUrl;
items[0].json.phoneSearched = rawPhone;
items[0].json.phoneWithNine = phoneWithNine;
items[0].json.phone11 = phone11;

return items;

const item = items[0].json;
const records = item.records || [];
const totalSize = item.totalSize || 0;
// Recupera dados do nó anterior (perdidos após o nó HTTP)
const prevNode = $node['Prepare SOQL Query'].json;
const phoneSearched = prevNode.phoneSearched || '';
const phoneWithNine = prevNode.phoneWithNine || '';
const instanceUrl = prevNode.sfInstanceUrl || '';

if (totalSize > 0 && records.length > 0) {
  const lead = records[0];
  const leadId = lead.Id;
  let lightningUrl = instanceUrl.replace('.my.salesforce.com', '.lightning.force.com');
  const leadUrl = lightningUrl + '/lightning/r/Lead/' + leadId + '/view';

  return [{
    json: {
      found: true,
      leadId: leadId,
      leadName: lead.Name || '',
      leadPhone: lead.Phone || '',
      leadMobile: lead.MobilePhone || '',
      beetalkPhone: lead.beetalk__PhoneOrMobilePhone__c || '',
      leadStatus: lead.Status || '',
      leadSource: lead.LeadSource || '',
      leadCompany: lead.Company || '',
      leadUrl: leadUrl,
      phoneSearched: phoneSearched,
      phoneWithNine: phoneWithNine
    }
  }];
} else {
  return [{
    json: {
      found: false,
      leadId: null,
      leadName: null,
      leadUrl: null,
      phoneSearched: phoneSearched,
      phoneWithNine: phoneWithNine,
      message: 'Nenhum Lead encontrado para o telefone ' + phoneWithNine
    }
  }];
}
